    private void handleIntent(@Nullable Intent intent) {
        if (intent == null) return;

        String action = intent.getAction();
        String type = intent.getType();

        StringBuilder debug = new StringBuilder();
        debug.append("action=").append(action).append('\n');
        debug.append("type=").append(type).append('\n');

        textView.setText("");
        imagesContainer.removeAllViews();

        String sharedText = extractSharedText(intent);
        if (sharedText != null && !sharedText.trim().isEmpty()) {
            textView.setText(sharedText);
        } else {
            textView.setText("(no text shared)");
        }

        List<Uri> imageUris = extractSharedUris(intent, debug);
        if (!imageUris.isEmpty()) {
            for (Uri uri : imageUris) {
                addImageRow(uri);
            }
        } else {
            TextView empty = new TextView(this);
            empty.setText("(no images shared)");
            empty.setTextSize(TypedValue.COMPLEX_UNIT_SP, 14);
            empty.setTextColor(0xFF666666);
            imagesContainer.addView(empty);
        }

        debugView.setText(debug.toString());
    }

    @Nullable
    private String extractSharedText(Intent intent) {
        String text = intent.getStringExtra(Intent.EXTRA_TEXT);
        if (text != null) return text;

        CharSequence cs = intent.getCharSequenceExtra(Intent.EXTRA_TEXT);
        if (cs != null) return cs.toString();

        String subject = intent.getStringExtra(Intent.EXTRA_SUBJECT);
        if (subject != null && !subject.isEmpty()) return subject;

        return null;
    }

    private List<Uri> extractSharedUris(Intent intent, StringBuilder debug) {
        List<Uri> uris = new ArrayList<>();

        Uri data = intent.getData();
        if (data != null) {
            debug.append("data=").append(data).append('\n');
            uris.add(data);
        }

        Uri stream = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (stream != null) {
            debug.append("EXTRA_STREAM=").append(stream).append('\n');
            uris.add(stream);
        }

        ArrayList<Uri> streams = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
        if (streams != null && !streams.isEmpty()) {
            debug.append("EXTRA_STREAM(list) size=").append(streams.size()).append('\n');
            uris.addAll(streams);
        }

        ClipData clipData = intent.getClipData();
        if (clipData != null) {
            debug.append("clipData items=").append(clipData.getItemCount()).append('\n');
            for (int i = 0; i < clipData.getItemCount(); i++) {
                ClipData.Item item = clipData.getItemAt(i);
                Uri u = item.getUri();
                if (u != null) uris.add(u);
            }
        }

        List<Uri> filtered = new ArrayList<>();
        for (Uri u : uris) {
            if (u == null) continue;
            if (!filtered.contains(u)) filtered.add(u);
        }

        List<Uri> imagesOnly = new ArrayList<>();
        ContentResolver cr = getContentResolver();
        for (Uri u : filtered) {
            String mime = null;
            try {
                mime = cr.getType(u);
            } catch (Exception ignored) {
            }
            if (mime != null && mime.startsWith("image/")) {
                imagesOnly.add(u);
            } else {
                String s = u.toString();
                if (s.startsWith("content://") || s.startsWith("file://")) {
                    if (mime == null) {
                        imagesOnly.add(u);
                    }
                }
            }
        }

        debug.append("imageUris=").append(imagesOnly.size()).append('\n');
        return imagesOnly;
    }

    private void addImageRow(Uri uri) {
        LinearLayout row = new LinearLayout(this);
        row.setOrientation(LinearLayout.VERTICAL);
        row.setPadding(0, 0, 0, dp(14));
        row.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        ));

        TextView meta = new TextView(this);
        meta.setTextSize(TypedValue.COMPLEX_UNIT_SP, 12);
        meta.setTextColor(0xFF555555);
        meta.setText(buildMeta(uri));
        meta.setPadding(0, 0, 0, dp(6));
        row.addView(meta);

        ImageView iv = new ImageView(this);
        iv.setAdjustViewBounds(true);
        iv.setScaleType(ImageView.ScaleType.FIT_CENTER);
        iv.setBackgroundColor(0x11000000);
        iv.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        ));
        row.addView(iv);

        imagesContainer.addView(row);

        Bitmap bmp = decodeBitmap(uri, 1600, 1600);
        if (bmp != null) {
            iv.setImageBitmap(bmp);
        } else {
            TextView err = new TextView(this);
            err.setTextSize(TypedValue.COMPLEX_UNIT_SP, 12);
            err.setTextColor(0xFFAA0000);
            err.setGravity(Gravity.START);
            err.setText("Failed to load image: " + uri);
            row.addView(err);
        }
    }

    private String buildMeta(Uri uri) {
        String name = null;
        long size = -1;

        try (Cursor c = getContentResolver().query(uri, null, null, null, null)) {
            if (c != null && c.moveToFirst()) {
                int nameIdx = c.getColumnIndex(OpenableColumns.DISPLAY_NAME);
                if (nameIdx >= 0) name = c.getString(nameIdx);
                int sizeIdx = c.getColumnIndex(OpenableColumns.SIZE);
                if (sizeIdx >= 0) size = c.getLong(sizeIdx);
            }
        } catch (Exception ignored) {
        }

        StringBuilder sb = new StringBuilder();
        sb.append(uri.toString());
        if (name != null) sb.append("\nname=").append(name);
        if (size >= 0) sb.append("\nsize=").append(size).append(" bytes");
        return sb.toString();
    }

    @Nullable
    private Bitmap decodeBitmap(Uri uri, int reqW, int reqH) {
        try {
            BitmapFactory.Options opts = new BitmapFactory.Options();
            opts.inJustDecodeBounds = true;
            try (InputStream is = getContentResolver().openInputStream(uri)) {
                if (is == null) return null;
                BitmapFactory.decodeStream(is, null, opts);
            }

            opts.inSampleSize = calculateInSampleSize(opts, reqW, reqH);
            opts.inJustDecodeBounds = false;
            opts.inPreferredConfig = Bitmap.Config.ARGB_8888;

            try (InputStream is2 = getContentResolver().openInputStream(uri)) {
                if (is2 == null) return null;
                return BitmapFactory.decodeStream(is2, null, opts);
            }
        } catch (Exception e) {
            return null;
        }
    }

    private int calculateInSampleSize(BitmapFactory.Options options, int reqWidth, int reqHeight) {
        int height = options.outHeight;
        int width = options.outWidth;
        int inSampleSize = 1;

        if (height > reqHeight || width > reqWidth) {
            int halfHeight = height / 2;
            int halfWidth = width / 2;

            while ((halfHeight / inSampleSize) >= reqHeight && (halfWidth / inSampleSize) >= reqWidth) {
                inSampleSize *= 2;
            }
        }
        return Math.max(1, inSampleSize);
    }

    private int dp(int v) {
        return (int) TypedValue.applyDimension(
                TypedValue.COMPLEX_UNIT_DIP,
                v,
                getResources().getDisplayMetrics()
        );
    }
